		hasEngaged: false,
		currentAnimation: null,
		suppressTimeout: parseFloat($el.attr("ad-suppress-timeout") || "1") * 1000,
		suppressTimeoutSkip: ($el.attr("ad-suppress-timeout-skip") || "0") === "1",
