		startCount: 0,
		currentWindow: window,

		adEvents: {
			"opencanvas": "show",
			"closecanvas": "hide",
			"restartcanvas": "restart",
			"playtimeline": "playTimeline",
            "restarttimeline": "restartTimeline"
		},

		events: {
			"track": "track"
		},

		init: function(parent, currentWindow) {
			var self = this;

			if("undefined" !== typeof currentWindow) {
				self.currentWindow = currentWindow;
			}

			if(!!window.scrollConfiguredTimelines && !!window.scrollConfiguredTimelines[this.id]) {
				//todo need to handle stop, start, restart events, etc
				var timelines = window.scrollConfiguredTimelines[this.id];
				$.each(timelines, function(i, e) {
					e.call(this, window)
				});
			}

			reflowHover(window, $el, parent)

			this.loadChildren();
		},
		
		initFadeIns: function() {
			var maxFadeZIndex = 0;
			var maxFade = null;

			$("ad-behaviour[ad-action='fadein']", $el).each(function(ix, el) {
				var target = $("ad-layer[ad-layer-id='" + $(el).attr("ad-target") + "']");
				if(target.css("z-index") > maxFadeZIndex) {
					maxFadeZIndex = target.css("z-index");
					maxFade = target;
				}
			});
			
			if(maxFade != null) {
				maxFade.addClass("fade-in");
			}
		},

		show: function() {
			
			reflow.adunit().showCanvas(this);
			
		},

		hide: function() {
			//reflow.adunit().showCanvas(this);
		},
		
